	@Test
	void derivesRelationalOutputsAndScalarDependenciesAsPackedMasks() throws Exception {
		SimpleValueFactory values = SimpleValueFactory.getInstance();
		TupleExpr source = new Filter(
				new Join(
						new StatementPattern(Var.of("person"), Var.of("namePredicate", values.createIRI("urn:name")),
								Var.of("name")),
						new StatementPattern(Var.of("person"), Var.of("agePredicate", values.createIRI("urn:age")),
								Var.of("age"))),
				new Compare(Var.of("age"), new ValueConstant(values.createLiteral(18)), Compare.CompareOp.GE));

		PackedQuery query = PackedQueryCodec.encode(source);
		Method relationMask = PackedQuery.class.getDeclaredMethod("relOutputMaskId", int.class);
		Method scalarMask = PackedQuery.class.getDeclaredMethod("scalarDependencyMaskId", int.class);
		Method cardinality = PackedQuery.class.getDeclaredMethod("maskCardinality", int.class);
		relationMask.setAccessible(true);
		scalarMask.setAccessible(true);
		cardinality.setAccessible(true);
		int rootId = query.rootRelId();
		int conditionId = query.relPayload(rootId);

		assertEquals(3, cardinality.invoke(query, relationMask.invoke(query, rootId)));
		assertEquals(1, cardinality.invoke(query, scalarMask.invoke(query, conditionId)));
	}

