	@Test
	void workExhaustionReturnsTheExecutableIncumbentWithoutLiveMemoState() {
		SimpleValueFactory values = SimpleValueFactory.getInstance();
		StatementPattern large = pattern(values, "x", "urn:large", "largeValue", 1_000.0d);
		StatementPattern small = pattern(values, "x", "urn:small", "bridge", 10.0d);
		StatementPattern medium = pattern(values, "bridge", "urn:medium", "mediumValue", 100.0d);
		TupleExpr source = new Join(new Join(large, medium), small);

		PackedPlanningResult result = PackedCascadesPlanner.optimize(source, 0L, Long.MAX_VALUE);

		assertEquals(source, result.selectedPlan());
		assertTrue(result.workLimitReached());
		assertTrue(result.metrics().encodeNanos() >= 0L);
		for (RecordComponent component : PackedPlanningResult.class.getRecordComponents()) {
			assertTrue(component.getType() != PackedMemo.class, component::getName);
		}
	}

