	@Test
	void seedsAndSelectsFiniteCodeTypeAlternativeInsideDistinctAggregateGroup() {
		SimpleValueFactory values = SimpleValueFactory.getInstance();
		TupleExpr union = new Union(codeTypeBranch(values, values.createIRI("urn:Condition")),
				codeTypeBranch(values, values.createIRI("urn:Medication")));
		LeftJoin withUnusedOptional = new LeftJoin(union,
				new StatementPattern(Var.of("entity"), Var.of("optional", values.createIRI("urn:optional")),
						Var.of("unused")));
		Group source = new Group(withUnusedOptional, List.of(),
				List.of(new GroupElem("count", new Count(Var.of("entity"), true))));

		PackedQuery query = PackedQueryCodec.encodeForPlanning(source);
		long generatedRuleMask = 0L;
		for (int relationId = 1; relationId <= query.relationCount(); relationId++) {
			generatedRuleMask |= query.relRuleMask(relationId);
		}
		PackedPlanningResult result = PackedCascadesPlanner.optimize(source, OptimizationGoal.root());

		assertTrue((generatedRuleMask & PackedRuleProofs.FINITE_CODE_TYPE_VALUES) != 0L);
		assertTrue((result.ruleProofMask() & PackedRuleProofs.FINITE_CODE_TYPE_VALUES) != 0L);
		assertFalse(result.selectedPlan().toString().contains("Union"), result.selectedPlan()::toString);
		assertTrue(result.selectedPlan().toString().contains("BindingSetAssignment ([[code="),
				result.selectedPlan()::toString);
		assertTrue(result.selectedPlan().toString().contains("BindingSetAssignment ([[type="),
				result.selectedPlan()::toString);
	}

	private static TupleExpr codeTypeBranch(SimpleValueFactory values, Value type) {
		MapBindingSet first = new MapBindingSet(1);
		first.setBinding("target", values.createLiteral("DX-200"));
		MapBindingSet second = new MapBindingSet(1);
		second.setBinding("target", values.createLiteral("DX-201"));
		BindingSetAssignment targets = new BindingSetAssignment();
		targets.setBindingNames(new LinkedHashSet<>(List.of("target")));
		targets.setBindingSets(List.of(first, second));
		StatementPattern typePattern = new StatementPattern(Var.of("entity"), Var.of("rdfType", RDF.TYPE),
				Var.of("typeValue", type));
		StatementPattern codePattern = new StatementPattern(Var.of("entity"),
				Var.of("codePredicate", values.createIRI("urn:code")), Var.of("code"));
		Join scopedPatterns = new Join(typePattern, codePattern);
		scopedPatterns.setVariableScopeChange(true);
		Or condition = new Or(new Compare(Var.of("code"), Var.of("target"), Compare.CompareOp.EQ),
				new Compare(Var.of("code"), new ValueConstant(values.createLiteral("DX-202")),
						Compare.CompareOp.EQ));
		return new Filter(new Join(targets, scopedPatterns), condition);
	}

	private static StatementPattern pattern(SimpleValueFactory values, String subject, String predicate,
			String object, double rows) {
		StatementPattern pattern = new StatementPattern(Var.of(subject), Var.of(predicate, values.createIRI(predicate)),
				Var.of(object));
		if (Double.isFinite(rows)) {
			pattern.setResultSizeEstimate(rows);
		}
		return pattern;
	}
